function generateSentakuQuestion(
  examId: string,
  subjectId: string,
  subjectName: string,
  globalNumber: number
): Question {
  const pool = SENTAKU_POOLS[subjectId];
  const template = pool ? pool[Math.floor(Math.random() * pool.length)] : SENTAKU_POOLS.s1[0];
  // 本試験準拠：正答が重複しないことを保証（correctAnswers内でユニークな5つ）
  const uniqueCorrectAnswers = Array.from(new Set(template.correctAnswers));
  if (uniqueCorrectAnswers.length < template.correctAnswers.length) {
    console.warn(`[sampleData] 重複した正答が検出されました: ${template.text.slice(0, 40)}`);
  }
  // 正答を除いたadditionalChoicesを選択（重複排除）
  const correctSet = new Set(template.correctAnswers);
  const additionalUnique = template.additionalChoices.filter(c => !correctSet.has(c));
  const additionalUniqueDeduplicated = Array.from(new Set(additionalUnique));
  // 正確に20個の選択肢: correctAnswers(5) + additionalChoices(15)
  const uniqueCorrectAnswersForChoices = Array.from(new Set(template.correctAnswers));
  const allChoices20 = [...uniqueCorrectAnswersForChoices, ...additionalUniqueDeduplicated].slice(0, 20);
  if (allChoices20.length < 20) {
    console.warn(`[sampleData] 選択肢が20個未満です(${allChoices20.length}個): ${template.text.slice(0, 40)}`);
  }
  const displayChoices = [...allChoices20].sort(() => Math.random() - 0.5);

  // 互換性のための古い仕様のblanks
  const blanks = template.correctAnswers.map((correctAnswer, idx) => ({
    id: `blank_${idx}`,
    position: idx,
    correctAnswer,
    choices: displayChoices
  }));

  // 新しい仕様のsentakuDataを生成
  const blankLabels = ['ア', 'イ', 'ウ', 'エ', 'オ'];
  const answers: Record<string, string> = {};
  template.correctAnswers.forEach((ans, idx) => {
    answers[blankLabels[idx]] = ans;
  });

  const sentakuData = {
    blanks: blankLabels,
    choices: displayChoices,
    answers
  };

  return {
    id: `q_${examId}_${subjectId}_${Date.now()}_${Math.random()}`,
    examId,
    type: 'sentaku',
    subjectId,
    subjectName,
    questionNumber: 1,
    globalNumber,
    text: template.text,
    blanks,
    sentakuData,
    explanation: template.explanation,
    tags: [subjectName],
    difficulty: 5,
  };
}

function shuffleArray<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function generateTakuitsuQuestion(
  examId: string,
  subjectId: string,
  subjectName: string,
  template: {text:string; choices:string[]; correctIdx:number; explanation:string},
  questionNumber: number,
  globalNumber: number
): Question {
  return {
    id: `q_${examId}_${subjectId}_${questionNumber}`,
    examId,
    type: 'takuitsu',
    subjectId,
    subjectName,
    questionNumber,
    globalNumber,
    text: template.text,
    choices: template.choices,
    correctAnswer: String(template.correctIdx + 1),
    explanation: template.explanation,
    tags: [subjectName],
    difficulty: 5,
  };
}

export function generateSentakuExam(): { exam: Exam; questions: Question[] } {
  const examId = `exam_sentaku_${Date.now()}`;
  const exam: Exam = {
    id: examId,
    title: '令和6年度 社会保険労務士試験 選択式（午前）',
    description: '1科目1問（5空欄）：全8科目40点満点',
    type: 'sentaku',
    timeLimit: 80 * 60,
    subjects: SENTAKU_SUBJECTS,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  const questions: Question[] = [];
  let globalNumber = 1;
  for (const subject of SENTAKU_SUBJECTS) {
    questions.push(generateSentakuQuestion(examId, subject.id, subject.name, globalNumber++));
  }
  return { exam, questions };
}

export function generateTakuitsuExam(): { exam: Exam; questions: Question[] } {
  const examId = `exam_takuitsu_${Date.now()}`;
  const exam: Exam = {
    id: examId,
    title: '令和6年度 社会保険労務士試験 択一式（午後）',
    description: '1問1点：全7科目70点満点',
    type: 'takuitsu',
    timeLimit: 210 * 60,
    subjects: TAKUITSU_SUBJECTS,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  const questions: Question[] = [];
  let globalNumber = 1;
  for (const subject of TAKUITSU_SUBJECTS) {
    const pool = TAKUITSU_POOLS[subject.id] || [];
    const shuffled = shuffleArray(pool);
    for (let i = 0; i < 10; i++) {
      const template = shuffled[i % shuffled.length];
      questions.push(generateTakuitsuQuestion(examId, subject.id, subject.name, template, i + 1, globalNumber++));
    }
  }
  return { exam, questions };
}

// ── 科目別学習モード用エクスポート ──
export const ALL_STUDY_SUBJECTS = [
  ...TAKUITSU_SUBJECTS.map(s => ({ ...s, examType: 'takuitsu' as const })),
  ...SENTAKU_SUBJECTS.map(s => ({ ...s, examType: 'sentaku' as const })),
];

export function generateSubjectStudy(subjectId: string, count: number = 5): {
  subjectName: string;
  questions: Question[];
} {
  const examId = `study_${subjectId}_${Date.now()}`;
  const questions: Question[] = [];

  // 択一式科目の場合
  const takuitsuSubject = TAKUITSU_SUBJECTS.find(s => s.id === subjectId);
  if (takuitsuSubject) {
    const pool = TAKUITSU_POOLS[subjectId] || [];
    const shuffled = shuffleArray(pool).slice(0, count);
    shuffled.forEach((template, i) => {
      questions.push(generateTakuitsuQuestion(examId, subjectId, takuitsuSubject.name, template, i + 1, i + 1));
    });
    return { subjectName: takuitsuSubject.name, questions };
  }

  // 選択式科目の場合
  const sentakuSubject = SENTAKU_SUBJECTS.find(s => s.id === subjectId);
  if (sentakuSubject) {
    const count2 = Math.min(count, SENTAKU_POOLS[subjectId]?.length || 1);
    const shuffled = shuffleArray(SENTAKU_POOLS[subjectId] || []).slice(0, count2);
    shuffled.forEach((_, i) => {
      questions.push(generateSentakuQuestion(examId, subjectId, sentakuSubject.name, i + 1));
    });
    return { subjectName: sentakuSubject.name, questions };
  }

  return { subjectName: '', questions: [] };
}
